#!/usr/bin/env python3
"""
PR Analyzer for DreamServer audit.
Extracts PR metadata, diffs, and generates initial analysis artifacts.
"""
import json
import subprocess
import os
import sys
from pathlib import Path

REPO_DIR = Path("/workspace/dreamserver-repo")
AUDIT_DIR = Path("/workspace/dreamserver-audit")

def load_prs():
    with open("/tmp/prs_page1.json") as f:
        return json.load(f)

def get_diff(pr_number):
    """Get the diff for a PR by comparing against main."""
    result = subprocess.run(
        ["git", "diff", f"origin/main...pr-{pr_number}"],
        cwd=REPO_DIR,
        capture_output=True, text=True, timeout=30
    )
    return result.stdout

def get_changed_files(pr_number):
    """Get list of changed files for a PR."""
    result = subprocess.run(
        ["git", "diff", "--name-only", f"origin/main...pr-{pr_number}"],
        cwd=REPO_DIR,
        capture_output=True, text=True, timeout=30
    )
    return [f for f in result.stdout.strip().split('\n') if f]

def get_stats(pr_number):
    """Get diff stats for a PR."""
    result = subprocess.run(
        ["git", "diff", "--stat", f"origin/main...pr-{pr_number}"],
        cwd=REPO_DIR,
        capture_output=True, text=True, timeout=30
    )
    return result.stdout

def categorize_subsystem(filepath):
    """Categorize a file path into subsystems."""
    subsystems = set()
    if filepath.startswith('dream-server/bin/'):
        subsystems.add('host-agent')
    elif filepath.startswith('dream-server/dashboard/'):
        subsystems.add('dashboard-api')
    elif filepath.startswith('dream-server/ui/'):
        subsystems.add('dashboard-ui')
    elif filepath.startswith('installer/'):
        subsystems.add('installer')
    elif filepath.startswith('scripts/'):
        subsystems.add('scripts')
    elif filepath.startswith('extensions/'):
        subsystems.add('extensions')
    elif filepath.startswith('docs/'):
        subsystems.add('docs')
    elif filepath.startswith('.github/'):
        subsystems.add('ci')
    elif filepath.startswith('tests/'):
        subsystems.add('tests')
    elif 'macos' in filepath.lower() or 'apple' in filepath.lower() or 'silicon' in filepath.lower():
        subsystems.add('macos')
    elif 'windows' in filepath.lower() or '.ps1' in filepath:
        subsystems.add('windows')
    elif 'gpu' in filepath.lower() or 'rocm' in filepath.lower() or 'amd' in filepath.lower():
        subsystems.add('gpu')
    elif 'docker' in filepath.lower() or 'compose' in filepath.lower():
        subsystems.add('docker')
    elif 'dream-cli' in filepath or filepath.endswith('.sh'):
        subsystems.add('dream-cli')
    elif 'langfuse' in filepath.lower():
        subsystems.add('langfuse')
    elif 'jupyter' in filepath.lower():
        subsystems.add('jupyter')
    elif 'perplexica' in filepath.lower():
        subsystems.add('perplexica')
    elif 'openclaw' in filepath.lower():
        subsystems.add('openclaw')
    elif 'librechat' in filepath.lower():
        subsystems.add('librechat')
    elif 'anythingllm' in filepath.lower():
        subsystems.add('anythingllm')
    elif 'localai' in filepath.lower():
        subsystems.add('localai')
    elif 'continue' in filepath.lower():
        subsystems.add('continue')
    elif 'piper' in filepath.lower():
        subsystems.add('piper-audio')
    elif 'milvus' in filepath.lower():
        subsystems.add('milvus')
    elif 'embeddings' in filepath.lower():
        subsystems.add('embeddings')
    elif 'image-gen' in filepath.lower() or 'dreamforge' in filepath.lower():
        subsystems.add('image-gen')
    elif 'bootstrap' in filepath.lower():
        subsystems.add('bootstrap')
    elif 'env' in filepath.lower() or '.env' in filepath:
        subsystems.add('env-config')
    elif 'schema' in filepath.lower():
        subsystems.add('schema')
    elif 'security' in filepath.lower():
        subsystems.add('security')
    elif 'resources' in filepath.lower():
        subsystems.add('resources')
    elif 'mobile' in filepath.lower() or 'termux' in filepath.lower() or 'a-shell' in filepath.lower():
        subsystems.add('mobile')
    elif 'support' in filepath.lower() or 'diagnostics' in filepath.lower():
        subsystems.add('support')
    elif 'gpu_reassign' in filepath.lower() or 'gpu' in filepath.lower():
        subsystems.add('gpu')
    elif 'shell' in filepath.lower():
        subsystems.add('dream-cli')
    elif 'doctor' in filepath.lower():
        subsystems.add('dream-cli')
    elif 'list' in filepath.lower() or 'status' in filepath.lower():
        subsystems.add('dream-cli')
    elif 'validate' in filepath.lower():
        subsystems.add('dream-cli')
    elif 'setup' in filepath.lower():
        subsystems.add('setup')
    elif 'resolver' in filepath.lower():
        subsystems.add('resolver')
    elif 'host-agent' in filepath.lower():
        subsystems.add('host-agent')
    elif 'dashboard' in filepath.lower():
        subsystems.add('dashboard-api')
    elif 'dream-agent-key' in filepath.lower():
        subsystems.add('dream-cli')
    elif 'bash' in filepath.lower():
        subsystems.add('dream-cli')
    elif 'token' in filepath.lower():
        subsystems.add('security')
    elif 'cors' in filepath.lower():
        subsystems.add('security')
    elif 'p2p' in filepath.lower() or 'vast' in filepath.lower():
        subsystems.add('resources')
    elif 'incubator' in filepath.lower():
        subsystems.add('docs')
    elif 'privacy' in filepath.lower():
        subsystems.add('security')
    elif 'voice' in filepath.lower():
        subsystems.add('voice')
    elif 'settings' in filepath.lower():
        subsystems.add('dashboard-api')
    elif 'injection' in filepath.lower() or 'validation' in filepath.lower():
        subsystems.add('security')
    elif 'input' in filepath.lower():
        subsystems.add('security')
    return list(subsystems) if subsystems else ['other']

def analyze_pr(pr):
    """Analyze a single PR and return metadata."""
    number = pr["number"]
    head_ref = pr["head"]["ref"]
    author = pr["user"]["login"]
    title = pr["title"]
    body = pr.get("body", "") or ""
    created = pr["created_at"]
    updated = pr["updated_at"]
    labels = [l["name"] for l in pr.get("labels", [])]

    changed_files = get_changed_files(number)
    diff = get_diff(number)
    stats = get_stats(number)

    # Count lines changed
    lines_added = diff.count('\n+') - diff.count('\n+++')
    lines_removed = diff.count('\n-') - diff.count('\n---')

    # Categorize by subsystem
    subsystems = set()
    for f in changed_files:
        for s in categorize_subsystem(f):
            subsystems.add(s)

    return {
        "number": number,
        "title": title,
        "author": author,
        "head_ref": head_ref,
        "created": created,
        "updated": updated,
        "labels": labels,
        "changed_files": changed_files,
        "num_files": len(changed_files),
        "lines_added": lines_added,
        "lines_removed": lines_removed,
        "subsystems": list(subsystems),
        "body": body,
        "stats": stats,
        "diff": diff,
    }

def main():
    prs = load_prs()
    results = []
    for pr in prs:
        try:
            analysis = analyze_pr(pr)
            results.append(analysis)
            print(f"Analyzed PR #{analysis['number']}: {analysis['num_files']} files, +{analysis['lines_added']}/-{analysis['lines_removed']}")
        except Exception as e:
            print(f"Error analyzing PR #{pr['number']}: {e}")

    # Save full analysis
    with open(AUDIT_DIR / "analysis" / "pr-analysis.json", "w") as f:
        json.dump(results, f, indent=2)

    # Generate dependency graph data
    file_to_prs = {}
    for r in results:
        for f in r["changed_files"]:
            if f not in file_to_prs:
                file_to_prs[f] = []
            file_to_prs[f].append(r["number"])

    # Find overlapping PRs
    overlaps = []
    for f, pr_nums in file_to_prs.items():
        if len(pr_nums) > 1:
            overlaps.append({"file": f, "prs": pr_nums})

    with open(AUDIT_DIR / "analysis" / "overlaps.json", "w") as f:
        json.dump(overlaps, f, indent=2)

    print(f"\nTotal PRs analyzed: {len(results)}")
    print(f"Files touched by multiple PRs: {len(overlaps)}")

    # Subsystem summary
    subsystem_counts = {}
    for r in results:
        for s in r["subsystems"]:
            subsystem_counts[s] = subsystem_counts.get(s, 0) + 1
    print("\nPRs by subsystem:")
    for s, c in sorted(subsystem_counts.items(), key=lambda x: -x[1]):
        print(f"  {s}: {c}")

    # Author summary
    author_counts = {}
    for r in results:
        author_counts[r["author"]] = author_counts.get(r["author"], 0) + 1
    print("\nPRs by author:")
    for a, c in sorted(author_counts.items(), key=lambda x: -x[1]):
        print(f"  {a}: {c}")

if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
Batch PR Review Generator for DreamServer audit.
Generates initial review artifacts for all 75 PRs.
"""
import json
import subprocess
import os
from pathlib import Path
from datetime import datetime

REPO_DIR = Path("/workspace/dreamserver-repo")
AUDIT_DIR = Path("/workspace/dreamserver-audit")

def load_prs():
    with open("/tmp/prs_page1.json") as f:
        return json.load(f)

def load_analysis():
    with open(AUDIT_DIR / "analysis" / "pr-analysis.json") as f:
        return json.load(f)

def get_diff_content(pr_number):
    result = subprocess.run(
        ["git", "diff", f"origin/main...pr-{pr_number}"],
        cwd=REPO_DIR, capture_output=True, text=True, timeout=30
    )
    return result.stdout

def get_file_list(pr_number):
    result = subprocess.run(
        ["git", "diff", "--name-only", f"origin/main...pr-{pr_number}"],
        cwd=REPO_DIR, capture_output=True, text=True, timeout=30
    )
    return [f for f in result.stdout.strip().split('\n') if f]

def get_commit_log(pr_number):
    result = subprocess.run(
        ["git", "log", f"origin/main..pr-{pr_number}", "--oneline"],
        cwd=REPO_DIR, capture_output=True, text=True, timeout=30
    )
    return result.stdout.strip()

def detect_bounty_tier(title, body, lines_changed):
    """Detect which bounty tier a PR claims based on content."""
    body_lower = (body or "").lower()
    title_lower = title.lower()

    if 'large' in body_lower or 'large' in title_lower or '$400' in body_lower:
        return 'Large ($400)'
    elif 'medium' in body_lower or 'medium' in title_lower or '$150' in body_lower:
        return 'Medium ($150)'
    elif 'small' in body_lower or 'small' in title_lower or '$40' in body_lower:
        return 'Small ($40)'
    elif lines_changed > 500:
        return 'Implied Large (>500 lines)'
    elif lines_changed > 100:
        return 'Implied Medium (>100 lines)'
    else:
        return 'Implied Small (<100 lines)'

def assess_risk(analysis):
    """Assess risk score for a PR."""
    score = 0
    factors = []

    # Surface area
    num_files = analysis['num_files']
    if num_files > 20:
        score += 3
        factors.append(f"High surface area ({num_files} files)")
    elif num_files > 10:
        score += 2
        factors.append(f"Medium surface area ({num_files} files)")
    elif num_files > 3:
        score += 1
        factors.append(f"Low surface area ({num_files} files)")

    # Lines changed
    lines = analysis['lines_added'] + analysis['lines_removed']
    if lines > 1000:
        score += 3
        factors.append(f"Large diff ({lines} lines)")
    elif lines > 200:
        score += 2
        factors.append(f"Medium diff ({lines} lines)")
    elif lines > 50:
        score += 1
        factors.append(f"Small diff ({lines} lines)")

    # Core subsystems
    for s in analysis['subsystems']:
        if s in ('host-agent', 'installer', 'gpu', 'security'):
            score += 2
            factors.append(f"Core subsystem: {s}")
        elif s in ('dashboard-api', 'docker'):
            score += 1
            factors.append(f"Important subsystem: {s}")

    # Test coverage
    has_tests = any('test' in s for s in analysis['subsystems'])
    if not has_tests and analysis['num_files'] > 0:
        score += 1
        factors.append("No test files included")

    return min(score, 10), factors

def generate_initial_review(pr, analysis):
    """Generate initial review content for a PR."""
    number = pr['number']
    title = pr['title']
    author = pr['user']['login']
    body = pr.get('body', '') or ''
    created = pr['created_at']

    lines_changed = analysis['lines_added'] + analysis['lines_removed']
    bounty_tier = detect_bounty_tier(title, body, lines_changed)
    risk_score, risk_factors = assess_risk(analysis)
    commit_log = get_commit_log(number)

    # Determine initial verdict category
    is_docs = any(s == 'docs' for s in analysis['subsystems']) and analysis['lines_added'] < 500
    is_test = any(s == 'tests' for s in analysis['subsystems']) and analysis['lines_removed'] == 0
    is_dependabot = author == 'dependabot[bot]'
    is_deletion = analysis['lines_added'] == 0 and analysis['lines_removed'] > 0

    # Initial verdict heuristic
    if is_dependabot:
        verdict = "MERGE"
        verdict_reason = "Automated dependency update, low risk"
    elif is_docs and analysis['num_files'] < 10:
        verdict = "MERGE"
        verdict_reason = "Documentation update, low risk"
    elif is_test and analysis['num_files'] < 5:
        verdict = "MERGE"
        verdict_reason = "Test addition, no production code changed"
    elif is_deletion and analysis['num_files'] < 5:
        verdict = "MERGE"
        verdict_reason = "Dead code removal, low risk"
    elif lines_changed > 3000:
        verdict = "REVISE"
        verdict_reason = "Very large PR requires phased review"
    elif risk_score >= 7:
        verdict = "REVISE"
        verdict_reason = f"High risk score ({risk_score}/10), needs careful review"
    else:
        verdict = "PENDING"
        verdict_reason = "Requires detailed review"

    return {
        'number': number,
        'title': title,
        'author': author,
        'created': created,
        'bounty_tier': bounty_tier,
        'risk_score': risk_score,
        'risk_factors': risk_factors,
        'verdict': verdict,
        'verdict_reason': verdict_reason,
        'lines_changed': lines_changed,
        'num_files': analysis['num_files'],
        'subsystems': analysis['subsystems'],
        'commit_log': commit_log,
        'changed_files': analysis['changed_files'],
    }

def main():
    prs = load_prs()
    analysis = load_analysis()

    # Create lookup
    analysis_by_num = {a['number']: a for a in analysis}

    reviews = []
    for pr in prs:
        num = pr['number']
        if num in analysis_by_num:
            review = generate_initial_review(pr, analysis_by_num[num])
            reviews.append(review)

            # Write verdict.md
            pr_dir = AUDIT_DIR / f"prs" / f"pr-{num}"
            pr_dir.mkdir(parents=True, exist_ok=True)

            verdict_content = f"""# PR #{num}: {pr['title']}

## Verdict: {review['verdict']}

**Reason:** {review['verdict_reason']}

## Metadata
- **Author:** {review['author']}
- **Created:** {review['created']}
- **Bounty Tier:** {review['bounty_tier']}
- **Risk Score:** {review['risk_score']}/10
- **Files Changed:** {review['num_files']}
- **Lines Changed:** +{analysis_by_num[num]['lines_added']}/-{analysis_by_num[num]['lines_removed']}
- **Subsystems:** {', '.join(review['subsystems'])}

## Risk Factors
{chr(10).join(f"- {f}" for f in review['risk_factors'])}

## Changed Files
{chr(10).join(f"- {f}" for f in review['changed_files'][:20])}
{chr(10) + f"... and {len(review['changed_files']) - 20} more" if len(review['changed_files']) > 20 else ''}

## Commit History
```
{review['commit_log']}
```

## Next Steps
- [ ] Detailed line-by-line review
- [ ] Test execution
- [ ] Cross-PR conflict check
- [ ] Bounty tier validation
"""
            (pr_dir / "verdict.md").write_text(verdict_content)

            # Write summary.md
            summary_content = f"""# PR #{num} Summary

## What This PR Claims to Do
{pr.get('body', 'No description provided.')[:2000]}

## My Assessment
**Initial classification:** {review['verdict']}

This PR touches {review['num_files']} files across {', '.join(review['subsystems'])} subsystems.
It adds {analysis_by_num[num]['lines_added']} lines and removes {analysis_by_num[num]['lines_removed']} lines.

## Key Observations
- Author: {review['author']} ({"core contributor" if review['author'] == 'yasinBursali' else "external contributor"})
- Bounty tier claimed: {review['bounty_tier']}
- Risk score: {review['risk_score']}/10
"""
            (pr_dir / "summary.md").write_text(summary_content)

            # Write trace.md
            trace_content = f"""# Review Trace for PR #{num}

## Source References
- **PR URL:** https://github.com/Light-Heart-Labs/DreamServer/pull/{num}
- **Head SHA:** {pr['head']['sha']}
- **Head Ref:** {pr['head']['ref']}
- **Fork:** {pr['head']['repo']['full_name']}

## Diff Command
```bash
git diff origin/main...pr-{num}
```

## Files Reviewed
{chr(10).join(f"- {f}" for f in review['changed_files'])}

## Review Date
{datetime.now().isoformat()}
"""
            (pr_dir / "trace.md").write_text(trace_content)

            # Write diff-analysis.md
            diff_content = f"""# Diff Analysis for PR #{num}

## Claimed vs Actual Changes

### PR Title
{pr['title']}

### Files Changed ({review['num_files']})
{chr(10).join(f"- {f}" for f in review['changed_files'])}

### Line Changes
- Added: {analysis_by_num[num]['lines_added']}
- Removed: {analysis_by_num[num]['lines_removed']}
- Net: {analysis_by_num[num]['lines_added'] - analysis_by_num[num]['lines_removed']}

### Subsystems Touched
{chr(10).join(f"- {s}" for s in review['subsystems'])}

### Bounty Tier Assessment
Claimed: {review['bounty_tier']}
Assessment: {"Matches expected scope" if (review['bounty_tier'].startswith('Implied') or lines_changed < 500) else "Needs verification"}
"""
            (pr_dir / "diff-analysis.md").write_text(diff_content)

            # Write interactions.md (placeholder)
            (pr_dir / "interactions.md").write_text(f"""# Cross-PR Interactions for PR #{num}

## Files Touched
{chr(10).join(f"- {f}" for f in review['changed_files'])}

## Potential Conflicts
*To be completed after full dependency graph analysis.*

## Dependencies
*None identified yet.*
""")

            print(f"Generated review for PR #{num}: {review['verdict']}")

    # Save all reviews
    with open(AUDIT_DIR / "analysis" / "reviews.json", "w") as f:
        json.dump(reviews, f, indent=2)

    # Summary
    verdicts = {}
    for r in reviews:
        v = r['verdict']
        verdicts[v] = verdicts.get(v, 0) + 1

    print(f"\nInitial verdict distribution:")
    for v, c in sorted(verdicts.items()):
        print(f"  {v}: {c}")

if __name__ == "__main__":
    main()

